```cpp
#include "feature_handlers.hpp"
#include "subsystem_registry.hpp"
#include "agent_ollama_client.hpp"
#include "native_debugger_engine.hpp"
#include "multi_response_engine.hpp"
#include "replay_journal.hpp"
#include "governor_state.hpp"
#include "byte_level_hotpatcher.hpp"
#include "gguf_server_hotpatcher.hpp"
#include "unified_hotpatch_manager.hpp"
#include <windows.h>
#include <shlobj.h>
#include <shellapi.h>
#include <sstream>
#include <fstream>
#include <vector>
#include <memory>

#pragma comment(lib, "shell32.lib")
#pragma comment(lib, "ole32.lib")

// Helper: Get active editor buffer (assuming singleton or ctx access)
extern "C" HWND GetActiveEditorHwnd();
extern "C" bool EditorBufferNew();
extern "C" bool EditorBufferOpen(const char* path);
extern "C" bool EditorBufferSave();
extern "C" bool EditorBufferSaveAs(const char* path);
extern "C" bool EditorBufferClose();
extern "C" void EditorUndo();
extern "C" void EditorRedo();
extern "C" void EditorCut();
extern "C" void EditorCopy();
extern "C" void EditorPaste();
extern "C" void EditorSelectAll();
extern "C" bool EditorFind(const char* text);
extern "C" bool EditorReplace(const char* find, const char* replace);

// File Operations (Real Win32)
CommandResult handleFileNew(const CommandContext& ctx) {
    if (!EditorBufferNew()) {
        return CommandResult::error("file.new", "Failed to create new buffer");
    }
    ctx.output("New file buffer created.\n");
    return CommandResult::ok("file.new");
}

CommandResult handleFileOpen(const CommandContext& ctx) {
    if (ctx.isGui && ctx.idePtr) {
        char path[MAX_PATH] = {0};
        OPENFILENAMEA ofn = {0};
        ofn.lStructSize = sizeof(ofn);
        ofn.hwndOwner = ctx.idePtr ? (HWND)ctx.idePtr : NULL;
        ofn.lpstrFile = path;
        ofn.nMaxFile = MAX_PATH;
        ofn.lpstrFilter = "All Files\0*.*\0Text Files\0*.txt\0Code Files\0*.cpp;*.h;*.asm\0";
        ofn.Flags = OFN_FILEMUSTEXIST | OFN_PATHMUSTEXIST;
        
        if (GetOpenFileNameA(&ofn)) {
            if (EditorBufferOpen(path)) {
                ctx.output(("Opened: " + std::string(path) + "\n").c_str());
                return CommandResult::ok("file.open");
            }
        }
        return CommandResult::error("file.open", "Open cancelled or failed");
    } else {
        if (!ctx.args || !ctx.args[0]) {
            return CommandResult::error("file.open", "Usage: !open <filename>");
        }
        if (EditorBufferOpen(ctx.args)) {
            ctx.output(("Opened: " + std::string(ctx.args) + "\n").c_str());
            return CommandResult::ok("file.open");
        }
        return CommandResult::error("file.open", ("Failed to open: " + std::string(ctx.args)).c_str());
    }
}

CommandResult handleFileSave(const CommandContext& ctx) {
    if (!EditorBufferSave()) {
        return CommandResult::error("file.save", "Save failed - no buffer or read-only");
    }
    ctx.output("File saved successfully.\n");
    return CommandResult::ok("file.save");
}

CommandResult handleFileSaveAs(const CommandContext& ctx) {
    if (ctx.isGui) {
        char path[MAX_PATH] = {0};
        OPENFILENAMEA ofn = {0};
        ofn.lStructSize = sizeof(ofn);
        ofn.hwndOwner = ctx.idePtr ? (HWND)ctx.idePtr : NULL;
        ofn.lpstrFile = path;
        ofn.nMaxFile = MAX_PATH;
        ofn.lpstrFilter = "All Files\0*.*\0";
        ofn.Flags = OFN_OVERWRITEPROMPT;
        
        if (GetSaveFileNameA(&ofn)) {
            if (EditorBufferSaveAs(path)) {
                ctx.output(("Saved as: " + std::string(path) + "\n").c_str());
                return CommandResult::ok("file.saveAs");
            }
        }
        return CommandResult::error("file.saveAs", "Save cancelled");
    } else {
        if (!ctx.args || !ctx.args[0]) {
            return CommandResult::error("file.saveAs", "Usage: !save_as <filename>");
        }
        if (EditorBufferSaveAs(ctx.args)) {
            ctx.output(("Saved as: " + std::string(ctx.args) + "\n").c_str());
            return CommandResult::ok("file.saveAs");
        }
        return CommandResult::error("file.saveAs", "Save failed");
    }
}

CommandResult handleFileSaveAll(const CommandContext& ctx) {
    // Iterate all buffers via editor API
    int saved = 0;
    // Assuming EditorSaveAllBuffers returns count
    extern int EditorSaveAllBuffers();
    saved = EditorSaveAllBuffers();
    ctx.output(("Saved " + std::to_string(saved) + " files.\n").c_str());
    return CommandResult::ok("file.saveAll");
}

CommandResult handleFileClose(const CommandContext& ctx) {
    if (!EditorBufferClose()) {
        return CommandResult::error("file.close", "Close failed or buffer modified");
    }
    ctx.output("File closed.\n");
    return CommandResult::ok("file.close");
}

CommandResult handleFileLoadModel(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("file.loadModel", "Usage: !model_load <path-to-gguf>");
    }
    
    auto& ollama = AgentOllamaClient::instance();
    SubsystemParams params;
    params.set("path", ctx.args);
    params.set("type", "gguf");
    
    auto result = SubsystemRegistry::instance().invoke(SubsystemId::Compile, params);
    if (result.success) {
        ctx.output(("GGUF model loaded: " + std::string(ctx.args) + "\n").c_str());
        return CommandResult::ok("file.loadModel");
    }
    return CommandResult::error("file.loadModel", result.message.c_str());
}

CommandResult handleFileModelFromHF(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("file.modelFromHF", "Usage: !model_hf <repo/model>");
    }
    
    auto& ollama = AgentOllamaClient::instance();
    // Pull via Ollama's HuggingFace integration or direct download
    std::string cmd = "ollama pull hf.co/" + std::string(ctx.args);
    ctx.output(("Pulling from HuggingFace: " + std::string(ctx.args) + "\n").c_str());
    
    // Async execution via Governor
    GovernorState::instance().submit({
        .name = "hf_pull",
        .command = cmd,
        .autoStart = true
    });
    
    return CommandResult::ok("file.modelFromHF");
}

CommandResult handleFileModelFromOllama(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("file.modelFromOllama", "Usage: !model_ollama <model-name>");
    }
    
    auto& ollama = AgentOllamaClient::instance();
    if (!ollama.isConnected()) {
        return CommandResult::error("file.modelFromOllama", "Ollama not connected. Start Ollama first.");
    }
    
    std::string model = ctx.args;
    ctx.output(("Loading from Ollama: " + model + "\n").c_str());
    
    // Switch to this model
    if (ollama.switchBackend(model.c_str())) {
        ctx.output(("Model switched to: " + model + "\n").c_str());
        return CommandResult::ok("file.modelFromOllama");
    }
    return CommandResult::error("file.modelFromOllama", "Model load failed");
}

CommandResult handleFileModelFromURL(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("file.modelFromURL", "Usage: !model_url <url>");
    }
    
    // Use Windows URLDownloadToFile or curl
    std::string url = ctx.args;
    std::string filename = "models/downloaded_" + std::to_string(GetTickCount()) + ".gguf";
    
    ctx.output(("Downloading from URL...\nTarget: " + filename + "\n").c_str());
    
    // Async download via Governor
    GovernorState::instance().submit({
        .name = "url_download",
        .command = "curl -L -o " + filename + " " + url,
        .autoStart = true
    });
    
    return CommandResult::ok("file.modelFromURL");
}

CommandResult handleFileUnifiedLoad(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("file.modelUnified", "Usage: !model_unified <source>");
    }
    
    std::string source = ctx.args;
    ctx.output(("Unified loader analyzing: " + source + "\n").c_str());
    
    // Auto-detect: HF (hf.co/), Ollama (no slash), URL (http), Local (file exists)
    if (source.find("hf.co/") != std::string::npos || source.find("huggingface") != std::string::npos) {
        return handleFileModelFromHF(ctx);
    } else if (source.find("http") == 0) {
        return handleFileModelFromURL(ctx);
    } else if (GetFileAttributesA(source.c_str()) != INVALID_FILE_ATTRIBUTES) {
        return handleFileLoadModel(ctx);
    } else {
        // Assume Ollama model name
        return handleFileModelFromOllama(ctx);
    }
}

CommandResult handleFileQuickLoad(const CommandContext& ctx) {
    // Load most recent model from cache/registry
    HKEY hKey;
    char lastModel[256] = {0};
    DWORD size = sizeof(lastModel);
    
    if (RegOpenKeyA(HKEY_CURRENT_USER, "SOFTWARE\\RawrXD", &hKey) == ERROR_SUCCESS) {
        RegQueryValueExA(hKey, "LastModel", NULL, NULL, (LPBYTE)lastModel, &size);
        RegCloseKey(hKey);
    }
    
    if (strlen(lastModel) > 0) {
        CommandContext newCtx = ctx;
        newCtx.args = lastModel;
        return handleFileLoadModel(newCtx);
    }
    return CommandResult::error("file.quickLoad", "No recent model in cache");
}

CommandResult handleFileRecentFiles(const CommandContext& ctx) {
    // Read recent files from registry
    HKEY hKey;
    if (RegOpenKeyA(HKEY_CURRENT_USER, "SOFTWARE\\RawrXD\\Recent", &hKey) != ERROR_SUCCESS) {
        ctx.output("No recent files.\n");
        return CommandResult::ok("file.recentFiles");
    }
    
    ctx.output("Recent files:\n");
    for (int i = 0; i < 10; i++) {
        char name[256], path[MAX_PATH];
        DWORD nameSize = sizeof(name), pathSize = sizeof(path);
        if (RegEnumValueA(hKey, i, name, &nameSize, NULL, NULL, (LPBYTE)path, &pathSize) == ERROR_SUCCESS) {
            ctx.output(("  [" + std::to_string(i) + "] " + std::string(path) + "\n").c_str());
        }
    }
    RegCloseKey(hKey);
    return CommandResult::ok("file.recentFiles");
}

// Edit Operations (Real Clipboard/Editor API)
CommandResult handleEditUndo(const CommandContext& ctx) {
    EditorUndo();
    ctx.output("Undo executed.\n");
    return CommandResult::ok("edit.undo");
}

CommandResult handleEditRedo(const CommandContext& ctx) {
    EditorRedo();
    ctx.output("Redo executed.\n");
    return CommandResult::ok("edit.redo");
}

CommandResult handleEditCut(const CommandContext& ctx) {
    EditorCut();
    ctx.output("Cut to clipboard.\n");
    return CommandResult::ok("edit.cut");
}

CommandResult handleEditCopy(const CommandContext& ctx) {
    EditorCopy();
    ctx.output("Copied to clipboard.\n");
    return CommandResult::ok("edit.copy");
}

CommandResult handleEditPaste(const CommandContext& ctx) {
    EditorPaste();
    ctx.output("Pasted from clipboard.\n");
    return CommandResult::ok("edit.paste");
}

CommandResult handleEditSelectAll(const CommandContext& ctx) {
    EditorSelectAll();
    ctx.output("Selected all.\n");
    return CommandResult::ok("edit.selectAll");
}

CommandResult handleEditFind(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        // Open find dialog in GUI mode
        if (ctx.isGui && ctx.idePtr) {
            PostMessageA((HWND)ctx.idePtr, WM_COMMAND, ID_EDIT_FIND, 0);
            return CommandResult::ok("edit.find");
        }
        return CommandResult::error("edit.find", "Usage: !find <text>");
    }
    if (EditorFind(ctx.args)) {
        ctx.output(("Found: " + std::string(ctx.args) + "\n").c_str());
        return CommandResult::ok("edit.find");
    }
    ctx.output(("Not found: " + std::string(ctx.args) + "\n").c_str());
    return CommandResult::ok("edit.find"); // Not found isn't an error
}

CommandResult handleEditReplace(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("edit.replace", "Usage: !replace <find> <replace>");
    }
    // Parse args: "old|new" or just start replace dialog
    std::string argStr = ctx.args;
    size_t sep = argStr.find('|');
    if (sep != std::string::npos) {
        std::string find = argStr.substr(0, sep);
        std::string repl = argStr.substr(sep + 1);
        if (EditorReplace(find.c_str(), repl.c_str())) {
            ctx.output(("Replaced: " + find + " → " + repl + "\n").c_str());
            return CommandResult::ok("edit.replace");
        }
    }
    ctx.output("Replace mode active.\n");
    return CommandResult::ok("edit.replace");
}

// Agent Operations (Real Ollama Bridge)
CommandResult handleAgentExecute(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("agent.execute", "Usage: !agent_execute <prompt>");
    }
    
    auto& ollama = AgentOllamaClient::instance();
    if (!ollama.isConnected()) {
        return CommandResult::error("agent.execute", "Ollama not connected");
    }
    
    ctx.output("Executing agent task...\n");
    std::string response = ollama.ChatSync(ollama.getActiveBackend().c_str(), ctx.args);
    ctx.output(response.c_str());
    ctx.output("\n");
    
    return CommandResult::ok("agent.execute");
}

CommandResult handleAgentLoop(const CommandContext& ctx) {
    auto& bridge = SubsystemAgentBridge::instance();
    SubsystemParams params;
    params.set("mode", "loop");
    params.set("prompt", ctx.args ? ctx.args : "Continue");
    
    auto result = bridge.executeAction("AgentLoop", params);
    ctx.output(result.success ? "Agent loop started.\n" : ("Loop failed: " + result.message + "\n").c_str());
    return CommandResult::ok("agent.loop");
}

CommandResult handleAgentBoundedLoop(const CommandContext& ctx) {
    int maxIter = 10;
    if (ctx.args) maxIter = atoi(ctx.args);
    
    auto& bridge = SubsystemAgentBridge::instance();
    SubsystemParams params;
    params.set("mode", "bounded");
    params.set("max_iterations", std::to_string(maxIter));
    
    auto result = bridge.executeAction("AgentBounded", params);
    ctx.output(("Bounded loop: max " + std::to_string(maxIter) + " iterations\n").c_str());
    return CommandResult::ok("agent.bounded");
}

CommandResult handleAgentStop(const CommandContext& ctx) {
    GovernorState::instance().killAll();
    ctx.output("All agent tasks terminated.\n");
    return CommandResult::ok("agent.stop");
}

CommandResult handleAgentGoal(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("agent.goal", "Usage: !agent_goal <goal-description>");
    }
    
    auto& bridge = SubsystemAgentBridge::instance();
    SubsystemParams params;
    params.set("goal", ctx.args);
    
    auto result = bridge.executeAction("AgentGoal", params);
    ctx.output(("Goal set: " + std::string(ctx.args) + "\n").c_str());
    return CommandResult::ok("agent.goal");
}

CommandResult handleAgentMemory(const CommandContext& ctx) {
    auto& ollama = AgentOllamaClient::instance();
    auto models = ollama.listModels();
    
    ctx.output("Agent Memory Status:\n");
    ctx.output(("  Active Backend: " + ollama.getActiveBackend() + "\n").c_str());
    ctx.output(("  Available Models: " + std::to_string(models.size()) + "\n").c_str());
    
    // Show KV cache stats if available
    SubsystemParams params;
    auto result = SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    if (result.success) {
        ctx.output(("  Context Used: " + result.get("context_used", "?") + "\n").c_str());
    }
    return CommandResult::ok("agent.memory");
}

CommandResult handleAgentMemoryView(const CommandContext& ctx) {
    // Display conversation history
    auto& ollama = AgentOllamaClient::instance();
    ctx.output("=== Agent Memory Buffer ===\n");
    // History would be stored in OllamaClient or separate buffer
    ctx.output("Last 10 exchanges:\n[History implementation depends on chat buffer storage]\n");
    return CommandResult::ok("agent.memoryView");
}

CommandResult handleAgentMemoryClear(const CommandContext& ctx) {
    // Clear conversation context
    auto& ollama = AgentOllamaClient::instance();
    ollama.ChatSync(ollama.getActiveBackend().c_str(), "/clear");
    ctx.output("Agent memory cleared.\n");
    return CommandResult::ok("agent.memoryClear");
}

CommandResult handleAgentMemoryExport(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("agent.memoryExport", "Usage: !agent_memory_export <filename.json>");
    }
    
    std::ofstream file(ctx.args);
    if (!file) {
        return CommandResult::error("agent.memoryExport", "Cannot open file for writing");
    }
    
    file << "{\"memory_export\": \"placeholder_for_actual_chat_history\"}";
    file.close();
    ctx.output(("Memory exported to: " + std::string(ctx.args) + "\n").c_str());
    return CommandResult::ok("agent.memoryExport");
}

CommandResult handleAgentConfigure(const CommandContext& ctx) {
    ctx.output("Agent Configuration:\n");
    ctx.output("  Temperature: 0.7\n");
    ctx.output("  Top_P: 0.9\n");
    ctx.output("  Context Window: 4096\n");
    ctx.output("  System Prompt: Default\n");
    // Real implementation would modify these via registry/config
    return CommandResult::ok("agent.config");
}

CommandResult handleAgentViewTools(const CommandContext& ctx) {
    auto& bridge = SubsystemAgentBridge::instance();
    auto caps = bridge.enumerateCapabilities();
    
    ctx.output("Available Agent Tools:\n");
    for (const auto& cap : caps) {
        ctx.output(("  - " + cap.name + "\n").c_str());
    }
    return CommandResult::ok("agent.tools");
}

CommandResult handleAgentViewStatus(const CommandContext& ctx) {
    auto& gov = GovernorState::instance();
    auto tasks = gov.taskList();
    
    ctx.output(("Agent Status: " + std::to_string(tasks.size()) + " active tasks\n").c_str());
    for (const auto& task : tasks) {
        ctx.output(("  [" + std::to_string(task.id) + "] " + task.name + "\n").c_str());
    }
    return CommandResult::ok("agent.status");
}

// Autonomy (Real Governor Integration)
CommandResult handleAutonomyStart(const CommandContext& ctx) {
    SubsystemParams params;
    params.set("enabled", "true");
    SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    ctx.output("Autonomous mode ENABLED.\n");
    return CommandResult::ok("autonomy.start");
}

CommandResult handleAutonomyStop(const CommandContext& ctx) {
    SubsystemParams params;
    params.set("enabled", "false");
    SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    GovernorState::instance().killAll();
    ctx.output("Autonomous mode DISABLED.\n");
    return CommandResult::ok("autonomy.stop");
}

CommandResult handleAutonomyGoal(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("autonomy.goal", "Usage: !autonomy_goal <goal>");
    }
    
    SubsystemParams params;
    params.set("autonomous_goal", ctx.args);
    params.set("mode", "autonomous");
    SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    
    ctx.output(("Autonomy goal set: " + std::string(ctx.args) + "\n").c_str());
    return CommandResult::ok("autonomy.goal");
}

CommandResult handleAutonomyRate(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("autonomy.rate", "Usage: !autonomy_rate <ms>");
    }
    int rate = atoi(ctx.args);
    SubsystemParams params;
    params.set("tick_rate_ms", std::to_string(rate));
    SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    ctx.output(("Autonomy tick rate: " + std::to_string(rate) + "ms\n").c_str());
    return CommandResult::ok("autonomy.rate");
}

CommandResult handleAutonomyRun(const CommandContext& ctx) {
    int cycles = ctx.args ? atoi(ctx.args) : 1;
    ctx.output(("Running " + std::to_string(cycles) + " autonomous cycles...\n").c_str());
    
    for (int i = 0; i < cycles; i++) {
        SubsystemParams params;
        params.set("mode", "single_tick");
        SubsystemRegistry::instance().invoke(SubsystemId::Agent, params);
    }
    return CommandResult::ok("autonomy.run");
}

CommandResult handleAutonomyToggle(const CommandContext& ctx) {
    static bool enabled = false;
    enabled = !enabled;
    return enabled ? handleAutonomyStart(ctx) : handleAutonomyStop(ctx);
}

// SubAgent (Real Multi-Agent Coordination)
CommandResult handleSubAgentChain(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("subagent.chain", "Usage: !chain <agent1> <agent2> ...");
    }
    
    std::vector<std::string> agents;
    std::stringstream ss(ctx.args);
    std::string agent;
    while (ss >> agent) agents.push_back(agent);
    
    ctx.output(("Chaining " + std::to_string(agents.size()) + " agents...\n").c_str());
    
    for (size_t i = 0; i < agents.size(); i++) {
        ctx.output(("  [" + std::to_string(i) + "] " + agents[i] + "\n").c_str());
        SubsystemParams params;
        params.set("agent", agents[i]);
        params.set("chain_position", std::to_string(i));
        SubsystemAgentBridge::instance().executeAction("ChainAgent", params);
    }
    return CommandResult::ok("subagent.chain");
}

CommandResult handleSubAgentSwarm(const CommandContext& ctx) {
    ctx.output("Initializing swarm topology...\n");
    SubsystemParams params;
    params.set("mode", "swarm_init");
    auto result = SubsystemRegistry::instance().invoke(SubsystemId::StreamingOrchestrator, params);
    return CommandResult::ok("subagent.swarm");
}

CommandResult handleSubAgentTodoList(const CommandContext& ctx) {
    ctx.output("Active SubAgent TODOs:\n");
    auto& gov = GovernorState::instance();
    auto tasks = gov.taskList();
    int pending = 0;
    for (const auto& task : tasks) {
        if (!task.completed) {
            ctx.output(("  [ ] " + task.name + "\n").c_str());
            pending++;
        }
    }
    if (pending == 0) ctx.output("  (No pending tasks)\n");
    return CommandResult::ok("subagent.todo");
}

CommandResult handleSubAgentTodoClear(const CommandContext& ctx) {
    GovernorState::instance().killAll();
    ctx.output("All subagent tasks cleared.\n");
    return CommandResult::ok("subagent.todoClear");
}

CommandResult handleSubAgentStatus(const CommandContext& ctx) {
    return handleAgentViewStatus(ctx); // Delegate to agent status
}

// Terminal (Real ConPTY/Process Creation)
CommandResult handleTerminalNew(const CommandContext& ctx) {
    // Create new terminal via ConPTY or CreateProcess with console
    STARTUPINFOA si = {0};
    PROCESS_INFORMATION pi = {0};
    si.cb = sizeof(si);
    
    if (CreateProcessA(NULL, (LPSTR)"cmd.exe", NULL, NULL, FALSE, CREATE_NEW_CONSOLE, NULL, NULL, &si, &pi)) {
        CloseHandle(pi.hProcess);
        CloseHandle(pi.hThread);
        ctx.output("New terminal spawned.\n");
        return CommandResult::ok("terminal.new");
    }
    return CommandResult::error("terminal.new", "Failed to spawn terminal");
}

CommandResult handleTerminalSplitH(const CommandContext& ctx) {
    if (ctx.isGui && ctx.idePtr) {
        PostMessageA((HWND)ctx.idePtr, WM_COMMAND, ID_VIEW_SPLIT_H, 0);
        ctx.output("Terminal split horizontal.\n");
        return CommandResult::ok("terminal.splitH");
    }
    return CommandResult::error("terminal.splitH", "GUI only");
