        return CommandResult::error("file.modelUnified", "Usage: !model_unified <source>");
    }
    
    std::string source = ctx.args;
    ctx.output(("Unified loader analyzing: " + source + "\n").c_str());
    
    // Auto-detect: HF (hf.co/), Ollama (no slash), URL (http), Local (file exists)
    if (source.find("hf.co/") != std::string::npos || source.find("huggingface") != std::string::npos) {
        return handleFileModelFromHF(ctx);
    } else if (source.find("http") == 0) {
        return handleFileModelFromURL(ctx);
    } else if (GetFileAttributesA(source.c_str()) != INVALID_FILE_ATTRIBUTES) {
        return handleFileLoadModel(ctx);
    } else {
        // Assume Ollama model name
        return handleFileModelFromOllama(ctx);
    }
}

CommandResult handleFileQuickLoad(const CommandContext& ctx) {
