    HKEY hKey;
    char lastModel[256] = {0};
    DWORD size = sizeof(lastModel);
    
    if (RegOpenKeyA(HKEY_CURRENT_USER, "SOFTWARE\\RawrXD", &hKey) == ERROR_SUCCESS) {
        RegQueryValueExA(hKey, "LastModel", NULL, NULL, (LPBYTE)lastModel, &size);
        RegCloseKey(hKey);
