// Git (Real Process Execution)
CommandResult handleGitStatus(const CommandContext& ctx) {
    FILE* pipe = _popen("git status --short 2>&1", "r");
    if (!pipe) {
        return CommandResult::error("git.status", "Failed to run git");
    }
    
    char buffer[256];
    ctx.output("Git Status:\n");
    while (fgets(buffer, sizeof(buffer), pipe)) {
        ctx.output(buffer);
    }
    _pclose(pipe);
    return CommandResult::ok("git.status");
}

CommandResult handleGitCommit(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("git.commit", "Usage: !git_commit <message>");
    }
    
    std::string cmd = "git commit -m \"" + std::string(ctx.args) + "\" 2>&1";
    FILE* pipe = _popen(cmd.c_str(), "r");
    if (pipe) {
        char buffer[256];
        while (fgets(buffer, sizeof(buffer), pipe)) {
            ctx.output(buffer);
        }
        _pclose(pipe);
    }
    return CommandResult::ok("git.commit");
}

