// File Operations (Real Win32)
CommandResult handleFileNew(const CommandContext& ctx) {
    if (!EditorBufferNew()) {
        return CommandResult::error("file.new", "Failed to create new buffer");
    }
    ctx.output("New file buffer created.\n");
    return CommandResult::ok("file.new");
}

CommandResult handleFileOpen(const CommandContext& ctx) {
    if (ctx.isGui && ctx.idePtr) {
        char path[MAX_PATH] = {0};
        OPENFILENAMEA ofn = {0};
        ofn.lStructSize = sizeof(ofn);
        ofn.hwndOwner = ctx.idePtr ? (HWND)ctx.idePtr : NULL;
        ofn.lpstrFile = path;
        ofn.nMaxFile = MAX_PATH;
        ofn.lpstrFilter = "All Files\0*.*\0Text Files\0*.txt\0Code Files\0*.cpp;*.h;*.asm\0";
        ofn.Flags = OFN_FILEMUSTEXIST | OFN_PATHMUSTEXIST;
        
        if (GetOpenFileNameA(&ofn)) {
            if (EditorBufferOpen(path)) {
                ctx.output(("Opened: " + std::string(path) + "\n").c_str());
                return CommandResult::ok("file.open");
            }
        }
        return CommandResult::error("file.open", "Open cancelled or failed");
    } else {
        if (!ctx.args || !ctx.args[0]) {
            return CommandResult::error("file.open", "Usage: !open <filename>");
        }
        if (EditorBufferOpen(ctx.args)) {
            ctx.output(("Opened: " + std::string(ctx.args) + "\n").c_str());
            return CommandResult::ok("file.open");
        }
        return CommandResult::error("file.open", ("Failed to open: " + std::string(ctx.args)).c_str());
    }
}

CommandResult handleFileSave(const CommandContext& ctx) {
    if (!EditorBufferSave()) {
        return CommandResult::error("file.save", "Save failed - no buffer or read-only");
    }
    ctx.output("File saved successfully.\n");
    return CommandResult::ok("file.save");
}

CommandResult handleFileSaveAs(const CommandContext& ctx) {
    if (ctx.isGui) {
        char path[MAX_PATH] = {0};
        OPENFILENAMEA ofn = {0};
        ofn.lStructSize = sizeof(ofn);
        ofn.hwndOwner = ctx.idePtr ? (HWND)ctx.idePtr : NULL;
        ofn.lpstrFile = path;
        ofn.nMaxFile = MAX_PATH;
        ofn.lpstrFilter = "All Files\0*.*\0";
        ofn.Flags = OFN_OVERWRITEPROMPT;
        
        if (GetSaveFileNameA(&ofn)) {
            if (EditorBufferSaveAs(path)) {
                ctx.output(("Saved as: " + std::string(path) + "\n").c_str());
                return CommandResult::ok("file.saveAs");
