        if (EditorBufferSaveAs(ctx.args)) {
            ctx.output(("Saved as: " + std::string(ctx.args) + "\n").c_str());
            return CommandResult::ok("file.saveAs");
        }
        return CommandResult::error("file.saveAs", "Save failed");
