CommandResult handleEditReplace(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) {
        return CommandResult::error("edit.replace", "Usage: !replace <find> <replace>");
    }
    // Parse args: "old|new" or just start replace dialog
    std::string argStr = ctx.args;
    size_t sep = argStr.find('|');
    if (sep != std::string::npos) {
        std::string find = argStr.substr(0, sep);
        std::string repl = argStr.substr(sep + 1);
        if (EditorReplace(find.c_str(), repl.c_str())) {
            ctx.output(("Replaced: " + find + " → " + repl + "\n").c_str());
            return CommandResult::ok("edit.replace");
        }
    }
    ctx.output("Replace mode active.\n");
    return CommandResult::ok("edit.replace");
}

