// Implementation for !hotpatch_apply (Tier 1, #57)
CommandResult handleHotpatchApply(const CommandContext& ctx) {
    // Expected args: <address> <hex_bytes>
    SubsystemParams params;
    params.targetAddress = ctx.getArgAsHex(0);
    params.buffer = ctx.getArgAsBuffer(1);

    // Call the real injection subsystem (ID 2)
    SubsystemResult res = RAWRXD_INVOKE(SubsystemId::Inject, params);

    if (res.success) {
        ctx.output("Successfully patched memory at address.\n");
        return CommandResult::ok("patch.applied");
    }
    return CommandResult::error("Patch failed: " + res.errorMessage);
}

